import{c as e,Q as r,j as o,m as a}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"深度拆解：AI Agent Harness 的构造【译】 — @dotey","description":"","frontmatter":{"title":"深度拆解：AI Agent Harness 的构造【译】 — @dotey","author":"宝玉（@dotey）","date":"2026-05-10T00:00:00.000Z","source":"https://x.com/dotey/status/2053601852261110201","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-10-@dotey-110201.md","filePath":"research/tweets/2026-05-10-@dotey-110201.md","lastUpdated":1779894392000}'),n={name:"research/tweets/2026-05-10-@dotey-110201.md"};function s(i,t,l,g,d,h){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="深度拆解-ai-agent-harness-的构造【译】-—-dotey" tabindex="-1">深度拆解：AI Agent Harness 的构造【译】 — @dotey <a class="header-anchor" href="#深度拆解-ai-agent-harness-的构造【译】-—-dotey" aria-label="Permalink to &quot;深度拆解：AI Agent Harness 的构造【译】 — @dotey&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/dotey/status/2053601852261110201" target="_blank" rel="noreferrer">https://x.com/dotey/status/2053601852261110201</a><strong>作者</strong>：宝玉（@dotey） <strong>發布日期</strong>：2026-05-10 <strong>收錄日期</strong>：2026-05-11 <strong>類型</strong>：Twitter Article <strong>統計</strong>：474 likes · 113 retweets · 996 bookmarks · 108128 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>作者：@akshay_pachaar</p><p>本文将深入探讨 Anthropic、OpenAI、Perplexity 和 LangChain 究竟在开发什么。我们将聊聊编排循环、工具、记忆、上下文管理，以及那些将&quot;无状态&quot;的大语言模型（LLM）转变为全能智能体（Agent）的底层机制。</p><p>你可能已经开发过聊天机器人，甚至可能用一些工具搭建了一个 ReAct 循环 （ReAct：Reason + Act，一种让模型在行动前先进行推理的模式）。跑 Demo 的时候看着挺好，但一旦投入生产环境，系统就会开始掉链子：模型会忘记三步前做了什么，工具调用悄悄报错，上下文窗口（Context Window）里塞满了毫无意义的垃圾信息。</p><p>问题其实并不在模型本身，而在模型外围的基础设施。</p><p>LangChain 证明了这一点：他们仅仅通过改变包裹大语言模型的底层架构——模型没变，参数没变——就让系统在 TerminalBench 2.0 （一个衡量 AI 智能体处理命令行任务能力的权威基准测试） 上的排名从 30 名开外飙升到了第 5 名。另一项研究则通过让大语言模型自己去优化这套架构，实现了 76.4% 的通过率，甚至超过了人类精心设计的系统。</p><p>现在，这套基础设施有了一个正式的名字：<strong>AI Agent Harness</strong>。</p><p>虽然这个术语在 2026 年初才正式确立，但其核心理念早已存在。Harness是包裹在大语言模型之外的完整软件架构：它包括编排循环、工具、记忆、上下文管理、状态持久化、错误处理和护栏（Guardrails）。Anthropic 在其 Claude Code 文档中直截了当地指出：SDK（软件开发工具包）就是&quot;驱动 Claude Code 的 Agent Harness&quot;。OpenAI 的 Codex 团队也使用了同样的说法，明确将&quot;智能体&quot;和&quot;Harness&quot;等同，指代那些让大语言模型真正发挥作用的非模型架构。</p><p>我非常喜欢 LangChain 的 <strong>Vivek Trivedy 给出的定义公式</strong>：&quot;如果你不是模型本身，那你就是 Harness。&quot;</p><p>这里有一个经常让人搞混的区别：&quot;AI 智能体&quot;（Agent）是用户感知到的行为体现，它是一个有目标、会用工具、能自我纠错的实体；而**&quot;Harness&quot;**则是产生这种行为的背后机器。当有人说&quot;我开发了一个智能体&quot;时，他真正的意思是&quot;我开发了一套 Harness，并把它接入了模型&quot;。</p><p>Beren Millidge 在其 2023 年的博文中做了一个精准的类比：原生大语言模型就像一个没有内存、没有硬盘、也没有输入输出设备的 CPU。此时，上下文窗口充当了内存（快但容量有限），外部数据库扮演了硬盘（大但速度慢），工具集成则是设备驱动程序。而<strong>Harness，就是那个操作系统</strong>。正如 Millidge 所写：&quot;我们重新发明了冯·诺依曼架构（Von Neumann architecture）&quot;，因为这是任何计算系统最自然的抽象方式。</p><p>围绕模型，工程化可以分为三个同心圆层次：</p><ul><li><strong>提示词工程 (Prompt engineering)</strong>：精心设计模型接收到的指令。</li><li><strong>上下文工程 (Context engineering)</strong>：管理模型在什么时间点能看到什么内容。</li><li><strong>Harness 工程 (Harness engineering)</strong>：涵盖了上述两者，再加上整个应用架构：包括工具编排、状态持久化、错误恢复、验证循环、安全执行以及生命周期管理。</li></ul><p>Harness 不仅仅是一个包裹提示词的套壳（AI Wrapper），它是让智能体能够自主行动的完整系统。</p><p>综合 Anthropic、OpenAI、LangChain 以及广大从业者的实践经验，一个生产级的 Agent Harness 由 12 个不同的组件构成。让我们逐一拆解。</p><h2 id="_1-编排循环-the-orchestration-loop" tabindex="-1">1. 编排循环 (The Orchestration Loop) <a class="header-anchor" href="#_1-编排循环-the-orchestration-loop" aria-label="Permalink to &quot;1. 编排循环 (The Orchestration Loop)&quot;">​</a></h2><p>这是系统的&quot;心脏&quot;。它实现了&quot;思考 - 行动 - 观察&quot;（Thought-Action-Observation，简称 TAO）循环，也被称为 ReAct 循环。这个循环不停运转：整合提示词 -&gt; 调用大语言模型 -&gt; 解析输出 -&gt; 执行工具调用 -&gt; 反馈结果 -&gt; 重复，直到任务完成。</p><p>从技术实现上看，它通常只是一个 while 循环。但复杂的地方不在于循环本身，而在于循环所要处理的各种状态和逻辑。Anthropic 将他们的运行时描述为一个&quot;笨循环&quot;，所有的智慧都存在于模型之中，Harness 只负责管理回合的切换。</p><h2 id="_2-工具-tools" tabindex="-1">2. 工具 (Tools) <a class="header-anchor" href="#_2-工具-tools" aria-label="Permalink to &quot;2. 工具 (Tools)&quot;">​</a></h2><p>工具是智能体的&quot;双手&quot;。它们被定义为某种结构化模式（名称、描述、参数类型），并注入到模型的上下文中，让模型知道哪些工具可用。工具层负责注册、格式校验、参数提取、在**沙箱（Sandbox）**环境执行、结果捕获，并最终将结果格式化为模型可读的&quot;观察结果&quot;。</p><p>Claude Code 提供了六大类工具：文件操作、搜索、执行、网页访问、代码分析和子智能体创建。OpenAI 的 Agents SDK 则支持函数工具（通过 @function_tool 定义）、托管工具（如网页搜索、代码解释器、文件搜索）以及 MCP （Model Context Protocol，一种开放的工具接入标准） 服务器工具。</p><h2 id="_3-记忆-memory" tabindex="-1">3. 记忆 (Memory) <a class="header-anchor" href="#_3-记忆-memory" aria-label="Permalink to &quot;3. 记忆 (Memory)&quot;">​</a></h2><p>记忆在不同的时间尺度上运作。<strong>短期</strong>记忆是单次会话中的对话历史。<strong>长期</strong>记忆则跨越多个会话持久存在：Anthropic 使用项目文件和自动生成的 memory.md 文件；LangGraph 使用按命名空间组织的 JSON 存储；OpenAI 则支持由 SQLite 或 Redis 驱动的会话存储。</p><p>Claude Code 实现了三层记忆架构：一个轻量级索引（每条约 150 字符，始终加载）、按需调用的详细主题文件，以及仅通过搜索访问的原始对话记录。一个核心设计原则是：<strong>智能体将自己的记忆视为一种&quot;提示&quot;，在行动前必须根据实际状态进行验证</strong>。</p><h2 id="_4-上下文管理-context-management" tabindex="-1">4. 上下文管理 (Context Management) <a class="header-anchor" href="#_4-上下文管理-context-management" aria-label="Permalink to &quot;4. 上下文管理 (Context Management)&quot;">​</a></h2><p>这是许多智能体容易暗中翻车的地方。核心问题在于<strong>上下文腐烂</strong>：当关键信息处于窗口中间位置时，模型表现会下降 30% 以上（这就是斯坦福大学发现的&quot;迷失在中间&quot;现象）。即便是支持百万级 Token 的窗口，随着上下文的增长，指令遵循能力也会退化。</p><p>生产环境的应对策略包括：</p><ul><li><strong>压缩 (Compaction)</strong>：在接近限制时总结对话历史（Claude Code 会保留架构决策和未修复的 Bug，同时丢弃冗余的工具输出）。</li><li><strong>观察掩码 (Observation masking)</strong>：隐藏旧的工具输出，但保留工具调用的记录。</li><li><strong>即时检索 (Just-in-time retrieval)</strong>：只保留轻量级标识符，动态加载数据（Claude Code 倾向于使用 grep 或 head 命令，而不是加载整个文件）。</li><li><strong>子智能体委托</strong>：让每个子智能体进行深度探索，但仅返回 1000 到 2000 Token 的浓缩摘要。</li></ul><p>Anthropic 的上下文工程指南指出，目标是：找到能最大化达成目标概率的、信号最强的最小 Token 集合。</p><h2 id="_5-提示词构建-prompt-construction" tabindex="-1">5. 提示词构建 (Prompt Construction) <a class="header-anchor" href="#_5-提示词构建-prompt-construction" aria-label="Permalink to &quot;5. 提示词构建 (Prompt Construction)&quot;">​</a></h2><p>这决定了模型在每一步具体能看到什么。它是层级化的：系统提示词、工具定义、记忆文件、对话历史，以及当前的用户消息。</p><p>OpenAI 的 Codex 使用严格的优先级栈：服务器控制的系统消息（最高优先级）、工具定义、开发者指令、用户指令，最后才是对话历史。</p><h2 id="_6-输出解析-output-parsing" tabindex="-1">6. 输出解析 (Output Parsing) <a class="header-anchor" href="#_6-输出解析-output-parsing" aria-label="Permalink to &quot;6. 输出解析 (Output Parsing)&quot;">​</a></h2><p>现代 Harness 依赖于原生<strong>工具调用</strong>，即模型返回结构化的 tool_calls 对象，而不是需要费力解析的自由文本。Harness 会检查：是否有工具调用？如果有，执行并继续循环；如果没有，那当前的输出就是最终答案。</p><p>对于结构化输出，OpenAI 和 LangChain 都支持通过 <strong>Pydantic 模型</strong> （Python 中用于数据校验和格式化的库） 进行模式约束。</p><h2 id="_7-状态管理-state-management" tabindex="-1">7. 状态管理 (State Management) <a class="header-anchor" href="#_7-状态管理-state-management" aria-label="Permalink to &quot;7. 状态管理 (State Management)&quot;">​</a></h2><p>LangGraph 将状态模拟为在图形节点中流动的类型化字典。系统会在关键步骤进行&quot;存档&quot;（Checkpointing），这样即使中断也能恢复，甚至可以进行&quot;时间旅行&quot;式的调试。OpenAI 则提供了四种策略：应用内存、SDK 会话、服务器端 API 或轻量级的响应 ID 链。Claude Code 采用了不同的思路：将 Git 提交作为存档点，将进度文件作为结构化的草稿纸。</p><h2 id="_8-错误处理-error-handling" tabindex="-1">8. 错误处理 (Error Handling) <a class="header-anchor" href="#_8-错误处理-error-handling" aria-label="Permalink to &quot;8. 错误处理 (Error Handling)&quot;">​</a></h2><p>为什么这很重要？一个包含 10 个步骤的过程，即使每一步的成功率高达 99%，最终全流程的成功率也只有约 90.4%。错误是会滚雪球的。</p><p>LangGraph 将错误分为四类：临时性的（带延迟的重试）、模型可恢复的（将错误作为工具消息返回，让模型自己调整）、用户可修复的（暂停等待人类干预）以及意外错误（上报调试）。</p><h2 id="_9-护栏与安全-guardrails-and-safety" tabindex="-1">9. 护栏与安全 (Guardrails and Safety) <a class="header-anchor" href="#_9-护栏与安全-guardrails-and-safety" aria-label="Permalink to &quot;9. 护栏与安全 (Guardrails and Safety)&quot;">​</a></h2><p>OpenAI 的 SDK 实现了三个层级：输入护栏（在第一个智能体运行时检查）、输出护栏（检查最终结果）以及工具护栏（每次调用工具前检查）。一旦触发&quot;绊网&quot;（Tripwire）机制，智能体将立即停止。</p><p>Anthropic 在架构上将&quot;权限执行&quot;与&quot;模型推理&quot;分离。模型决定想做什么，但 Harness 决定允许做什么。</p><h2 id="_10-验证循环-verification-loops" tabindex="-1">10. 验证循环 (Verification Loops) <a class="header-anchor" href="#_10-验证循环-verification-loops" aria-label="Permalink to &quot;10. 验证循环 (Verification Loops)&quot;">​</a></h2><p>这是区分&quot;玩具演示&quot;和&quot;生产级智能体&quot;的关键。Anthropic 推荐三种方法：基于规则的反馈（测试、代码检查）、视觉反馈（通过 Playwright 截取 UI 截图）以及<strong>以大语言模型为裁判 (LLM-as-judge)</strong>（由另一个子智能体评估输出）。</p><p>Claude Code 的创造者 Boris Cherny 指出，让模型能够验证自己的工作，能让产出质量提升 2 到 3 倍。</p><h2 id="_11-子智能体编排-subagent-orchestration" tabindex="-1">11. 子智能体编排 (Subagent Orchestration) <a class="header-anchor" href="#_11-子智能体编排-subagent-orchestration" aria-label="Permalink to &quot;11. 子智能体编排 (Subagent Orchestration)&quot;">​</a></h2><p>Claude Code 支持三种模式：<strong>克隆 (Fork)</strong>（复制父级上下文）、<strong>队友 (Teammate)</strong>（通过文件邮箱通信的独立窗口）和<strong>工作树 (Worktree)</strong>（独立的 Git 分支）。OpenAI 则支持将智能体作为工具（专家处理特定子任务）或移交（专家接管后续控制权）。</p><p>既然了解了组件，让我们看看它们在一次循环中是如何协同工作的。</p><ol><li><strong>第一步（提示词组装）</strong>：Harness 构建完整的输入信息。</li><li><strong>第二步（模型推理）</strong>：组装好的内容发送给模型 API，模型生成 Token：可能是文本，也可能是工具调用请求。</li><li><strong>第三步（输出分类）</strong>：如果没有工具调用，循环结束；如果有，进入执行阶段。</li><li><strong>第四步（工具执行）</strong>：Harness 校验参数、检查权限，在沙箱中运行并捕获结果。</li><li><strong>第五步（结果打包）</strong>：将结果格式化为模型可读的消息，捕获错误以便模型自愈。</li><li><strong>第六步（上下文更新）</strong>：将结果追加到历史记录，必要时触发压缩。</li><li><strong>第七步（循环）</strong>：返回第一步，直到满足退出条件。</li></ol><hr><p>各框架实现对比：</p><ul><li><strong>Anthropic (Claude Agent SDK)</strong>：通过一个简单的 query() 函数暴露 Harness，运行时是一个&quot;笨循环&quot;，智慧全在模型里。</li><li><strong>OpenAI (Agents SDK)</strong>：采用&quot;代码优先&quot;策略，工作流逻辑直接用 Python 表达，而不是复杂的图形语言。</li><li><strong>LangGraph</strong>：将 Harness 建模为显式的状态图，强调对流程的精细控制。</li><li><strong>CrewAI</strong>：实现了基于角色的多智能体协作，由&quot;流程层&quot;管理确定性的骨干逻辑。</li><li><strong>AutoGen</strong>：由微软开发，支持多种编排模式，如顺序执行、群聊、移交和动态任务管理。</li></ul><p>&quot;脚手架&quot;这个比喻并非装饰，而是极其精准的。建筑脚手架是临时性的基础设施，让工人们能触及原本够不到的高度。脚手架本身不盖房子，但没有它，工人就上不去高层。</p><p><strong>关键洞察在于：房子盖好后，脚手架是要拆除的。</strong> 随着模型能力的提升，Harness 的复杂程度应该逐渐降低。</p><p>这就是<strong>协同进化原则</strong>：现在的模型在训练时，就已经考虑了 Harness 的存在。如果你的 Harness 设计得好，当模型升级时，你不需要增加复杂度，性能就会自动提升。</p><hr><p>每个 Harness 的架构师都面临这七个选择：</p><ol><li><strong>单智能体 vs. 多智能体</strong>：官方建议：先充分挖掘单智能体的潜力。多智能体会带来额外的开销和信息损耗。</li><li><strong>ReAct vs. 先规划后执行</strong>：ReAct 灵活但成本高；&quot;先规划后执行&quot;速度更快。</li><li><strong>上下文管理策略</strong>：是总结对话，还是动态加载？</li><li><strong>验证循环设计</strong>：是用硬性的代码测试，还是用另一个 LLM 来打分？</li><li><strong>权限与安全架构</strong>：是追求速度自动批准，还是追求安全步步确认？</li><li><strong>工具范围管理</strong>：工具不是越多越好。暴露当前步骤所需的最小工具集往往效果最佳。</li><li><strong>Harness 的厚度</strong>：多少逻辑写死在系统里，多少逻辑留给模型发挥？</li></ol><p>两个使用完全相同模型的智能体，性能可能天差地别，原因就在于 Harness 的设计。TerminalBench 的证据已经非常明确：仅仅改变 Harness，就能让排名变动 20 多位。</p><p>Harness 不是一个已经解决的问题，也不是一个通用的商品层。它是硬核工程能力的体现：如何将上下文视为稀缺资源进行管理？如何设计验证循环以防止错误累积？如何构建不产生幻觉的记忆系统？</p><p>随着模型越来越强，Harness 会变薄，但它永远不会消失。即便最强大的模型，也需要系统来管理窗口、执行代码、保存状态并验证工作。</p><p>下次当你的智能体表现不佳时，别光顾着抱怨模型，去检查一下你的 <strong>Harness</strong> 吧。</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：AI Agent 性能差距來自 Harness 設計，而非模型本身；掌握 12 個 Harness 組件是生產級 Agent 的關鍵。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li>問題不在模型，在模型外圍——LangChain 僅改 Harness 架構，TerminalBench 排名從 30 名飆升至第 5 名，模型未動</li><li>Harness 的定義公式：「如果你不是模型本身，那你就是 Harness」（Vivek Trivedy, LangChain）</li><li>三個同心圓工程層級：提示詞工程 → 上下文工程 → Harness 工程（最外層、最完整）</li><li>生產級 Harness 的 12 個組件：編排循環、工具、記憶、上下文管理、提示詞構建、輸出解析、狀態管理、錯誤處理、護欄安全、驗證循環、子智能體編排</li><li>協同進化原則：Harness 設計越好，模型升級時性能自動提升，無需增加複雜度</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>TerminalBench 2.0：改 Harness（不改模型）排名跳升 20+ 位（LangChain 從 30 名外 → 第 5 名）</li><li>LLM 自優化 Harness：76.4% 通過率，超越人類精心設計的系統</li><li>上下文腐爛：關鍵資訊在窗口中間時模型表現下降 30%（Stanford「迷失在中間」研究）</li><li>Boris Cherny（Claude Code 創造者）：自我驗證機制讓輸出品質提升 2-3 倍</li><li>Beren Millidge 類比：LLM = CPU，Context Window = 記憶體，外部 DB = 硬碟，工具集成 = 驅動程式，Harness = OS</li><li>框架對比：Anthropic Claude Agent SDK、OpenAI Agents SDK、LangGraph、CrewAI、AutoGen（微軟）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li>「協同進化原則」（Harness 越薄越好）缺乏量化驗證—何時適合減薄需具體模型能力基準才能判斷，目前為定性主張</li><li>12 個組件分類與框架 SDK 緊密綁定（Anthropic/OpenAI/LangGraph），跨框架通用定義未被明確，實際邊界可能因實作而模糊</li><li>TerminalBench 及「76.4% 通過率」等核心數據未附原始文獻連結，無法獨立驗證（原文作者 @akshay_pachaar 的鏈接缺失）</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>12 個組件可直接對照 cc-workspace 的 harness-design.md，實作參考價值高</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>「Harness」術語正式化 + 多框架統一比較為新貢獻，但組件概念工程界已廣知</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>有 TerminalBench、76.4% 等具體數據，但原始文獻鏈接缺失，難以獨立驗證</td></tr><tr><td>D. 技術深度 (15%)</td><td>8/10</td><td>涵蓋 5 大框架實作細節，含具體 API（query()、@function_tool、LangGraph 狀態圖）</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>原則適用於任何 LLM Agent 系統，不限框架或模型</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.4/10</strong></td><td>8×0.3+7×0.2+6×0.2+8×0.15+8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：核心為通用 Harness 設計原則（12 組件框架 + 7 架構決策點），適合轉化為 workspace 設計規則，補充 harness-design.md</p>',79)])])}const c=e(n,[["render",s]]);export{u as __pageData,c as default};
